    int p = 1;

    for (int i = n-1; i >= 0; ) {
        int group = 0;
        group += num[i] - '0';
        i--;
        group += (num[i] - '0') * 10;
        i--;
        group += (num[i] - '0') * 100;
        i--;
        GSum = GSum + group * p;
        p *= (-1);
    }
    return (GSum % 7 == 0);
}
