int sortedCount(int mat[][1000], int r, int c) {
    int result = 0;

    // Check for ascending sorted rows
    for (int i = 0; i < r; i++) {
        int j = 0;
        for (j = 0; j < c - 1; j++) {
            if (mat[i][j + 1] <= mat[i][j]) {
                break;
