#include <cmath>
#include <vector>

int discreteLogarithm(int a, int b, int m) {
    int n = static_cast<int>(sqrt(m) + 1);
    int an = 1;
    for (int i = 0; i < n; i++) {
        an = (1LL * an * a) % m;
    }

    std::vector<int> value(m, 0);
    int cur = an;
    for (int i = 1; i <= n; i++) {
        if (value[cur] == 0) {
            value[cur] = i;
        }
        cur = (1LL * cur * an) % m;
    }

    cur = b;
    for (int i = 0; i <= n; i++) {
        if (value[cur] > 0) {
            int ans = value[cur] * n - i;
            if (ans < m) {
                return ans;
            }
        }
        cur = (1LL * cur * a) % m;
    }

    return -1;
}
