int minPalPartion(string str) {
    int n = str.length();
    vector<vector<int>> C(n, vector<int>(n, 0));
    vector<vector<bool>> P(n, vector<bool>(n, false));

    // Initialize single characters as palindromes with 0 cuts
    for (int i = 0; i < n; i++) {
        P[i][i] = true;
        C[i][i] = 0;
    }

    // Check for palindromes of length 2 to n
    for (int L = 2; L <= n; L++) {
        for (int i = 0; i <= n - L; i++) {
            int j = i + L - 1;

            if (L == 2) {
                P[i][j] = (str[i] == str[j]);
            } else {
                P[i][j] = (str[i] == str[j]) && P[i + 1][j - 1];
            }

            if (P[i][j] == true) {
                C[i][j] = 0;
            } else {
                C[i][j] = 100000000;
                for (int k = i; k < j; k++) {
                    C[i][j] = min(C[i][j], C[i][k] + C[k + 1][j] + 1);
                }
            }
        }
    }

    return C[0][n - 1];
}
