int findFourElements(vector<int>& arr, int n) {
    map<int, pair<int, int>> mp;

    // Build map of sums to index pairs
    for (int i = 0; i < n - 1; i++) {
        for (int j = i + 1; j < n; j++) {
            mp[arr[i] + arr[j]] = make_pair(i, j);
        }
    }

    int d = -1000000000;  // -10^9

    // Check for valid four elements
    for (int i = 0; i < n - 1; i++) {
        for (int j = i + 1; j < n; j++) {
            int abs_diff = abs(arr[i] - arr[j]);

            if (mp.find(abs_diff) != mp.end()) {
                pair<int, int> p = mp[abs_diff];

                if (p.first != i && p.first != j && p.second != i && p.second != j) {
                    d = max(d, max(arr[i], arr[j]));
