int binaryMedian(std::vector<std::vector<int>>& m, int r, int c) {
    int mi = INT_MAX;
    int mx = INT_MIN;

    for (int i = 0; i < r; i++) {
        if (m[i][0] < mi) {
            mi = m[i][0];
        }
        if (m[i][c - 1] > mx) {
            mx = m[i][c - 1];
        }
    }

    int desired = (r * c + 1) / 2;

    while (mi < mx) {
        int mid = mi + (mx - mi) / 2;
        int place = 0;

        for (int i = 0; i < r; i++) {
            int j = upper_bound(m[i], mid);
            place = place + j;
        }

        if (place < desired) {
            mi = mid + 1;
        } else {
            mx = mid;
        }
    }

    std::cout << "Median is " << mi << std::endl;
    return mi;
}
