#include <string>
#include <algorithm>

bool prevPermutation(std::string& str) {
    int n = str.length() - 1;
    int i = n;

    while (i > 0 && str[i - 1] <= str[i]) {
        i--;
    }

    if (i <= 0) {
        return false;
    }

    int j = i - 1;
    while (j + 1 <= n && str[j + 1] <= str[i - 1]) {
        j++;
    }

    // Swap characters
    char temp = str[i - 1];
    str[i - 1] = str[j];
    str[j] = temp;

    // Reverse the substring from position i to end
    std::reverse(str.begin() + i, str.end());

    return true;
}
