int largestSumOfAverages(vector<int>& A, int K) {
    int n = A.size();
    vector<double> pre_sum(n + 1, 0);

    // Calculate prefix sums
    for (int i = 0; i < n; i++) {
        pre_sum[i + 1] = pre_sum[i] + A[i];
    }

    // Initialize dp array with averages from each position to end
    vector<double> dp(n);
    for (int i = 0; i < n; i++) {
        dp[i] = (pre_sum[n] - pre_sum[i]) / (n - i);
    }

    // Perform K-1 iterations to find optimal splits
    for (int k = 0; k < K - 1; k++) {
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                dp[i] = max(dp[i], (pre_sum[j] - pre_sum[i]) / (j - i) + dp[j]);
            }
        }
    }

    return (int)dp[0];
}
